mapper.select:
SELECT wq.question_id AS questionId, q.content AS questionContent, SUM(wq.wrong_count) AS totalWrongCount FROM wrong_question wq JOIN question q ON wq.question_id = q.id AND q.deleted = 0
AND wq.bank_id = #{bankId}
GROUP BY wq.question_id, q.content ORDER BY totalWrongCount DESC LIMIT #{limit}
